import json
import re

# Load books and extract years
books_data = json.load(open(locals()['var_functions.query_db:24']))
books_with_years = []

for book in books_data:
    details = book.get('details', '')
    years = re.findall(r'\b(19\d{2}|20[0-2]\d)\b', details)
    for year_str in years:
        year = int(year_str)
        if 1900 <= year <= 2023:
            decade = (year // 10) * 10
            books_with_years.append({
                'id': book['book_id'],
                'year': year,
                'decade': decade
            })
            break

print('Books processed:', len(books_data))
print('Books with years:', len(books_with_years))

# Load reviews
reviews_data = json.load(open(locals()['var_functions.query_db:22']))
reviews_processed = []

for review in reviews_data:
    try:
        rating = float(review['rating'])
        match = re.search(r'(\d+)$', review['purchase_id'])
        if match:
            reviews_processed.append({
                'rating': rating,
                'num_id': match.group(1)
            })
    except:
        pass

print('Reviews processed:', len(reviews_processed))

# Match reviews to books
book_map = {}
for book in books_with_years:
    match = re.search(r'(\d+)$', book['id'])
    if match:
        book_map[match.group(1)] = book

matched = []
for review in reviews_processed:
    book = book_map.get(review['num_id'])
    if book:
        matched.append({
            'decade': book['decade'],
            'rating': review['rating']
        })

print('Matched reviews:', len(matched))

# Calculate decade averages
from collections import defaultdict
decades = defaultdict(lambda: {'ratings': []})

for item in matched:
    dec = item['decade']
    dec = str(dec)
    if not dec.endswith('s'):
        dec = dec + 's'
    decades[dec]['ratings'].append(item['rating'])

results = []
for decade, stats in decades.items():
    if len(stats['ratings']) >= 10:
        avg = sum(stats['ratings']) / len(stats['ratings'])
        results.append({
            'decade': decade,
            'avg': avg,
            'count': len(stats['ratings'])
        })

results.sort(key=lambda x: x['avg'], reverse=True)

print('Decades found:', len(results))
if results:
    print('Top decade:', results[0])

best_decade = results[0]['decade'] if results else None

print('__RESULT__:')
print(json.dumps(best_decade))

